VALUES
  ('judicial-57112235-moex-00307', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲欲殺乙，夜裡持槍至乙宅瘋狂掃射，所幸乙事先獲悉風聲，早一步逃離。關於甲的行為，依實務見解， 下列何者正確？', '["普通未遂", "不能未遂", "打擊錯誤", "客體錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00308', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '對於刑法故意犯「行為階段」的流程，下列敘述何者正確？', '["決意、陰謀、預備、著手實行", "陰謀、預備、決意、著手實行", "決意、預備、陰謀、著手實行", "預備、決意、陰謀、著手實行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00309', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '30歲的甲欲參加歌唱選秀，但因該比賽限定未滿22歲的大學生始可報名參加，因此甲乃竄改其報名文件 上身分證影本的出生年月日，使其符合報名標準，主辦單位因而誤信為真而核准其參賽資格。依實務見解， 甲可能成立何罪？', '["行使變造私文書罪", "行使變造公文書罪", "行使變造特種文書罪", "行使業務登載不實文書罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00310', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何者行為不能算為共同正犯？', '["與他人犯意聯絡並參與部分構成要件實行", "與他人碰巧在相同的時間與場所犯罪", "與他人謀議並一同實行犯罪", "與他人犯意聯絡並參與全部構成要件實行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00311', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關教唆犯之處罰，依刑法規定與實務見解，下列敘述何者正確？', '["被教唆之正犯即使未至犯罪，教唆犯仍以未遂犯論", "教唆犯僅是教唆他人犯罪，並未親自實行犯罪行為，因而就教唆犯之處罰，得按正犯之刑減輕之", "刑法第153條煽惑他人犯罪罪與教唆犯並無不同", "教唆他人犯罪後，又參加實行構成要件行為者，應成立共同正犯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00312', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲教唆乙殺害A，同時給了乙一把開山刀，未料乙據開山刀為己有，未前往殺A。有關甲、乙之刑責，下 列敘述何者正確？', '["甲成立殺人未遂罪之教唆犯", "甲成立殺人預備罪之教唆犯", "乙成立侵占罪", "乙成立竊盜罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00313', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列情形中，何者之行為成立教唆犯？', '["甲發起抗稅運動，在網路上呼籲全民拒繳稅金，果真有大批民眾未繳納稅金", "乙知友人欲行竊某豪宅，傳訊給予加油鼓勵，友人因而行竊成功", "丙欺騙不知情的路人，某輛他人腳踏車為自己所有，請路人幫忙牽到丙宅停放", "丁在夜店受到欺負，向其男友哭訴，並要男友教訓該人，男友便痛毆該人一頓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00314', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何者是義務沒收的客體？', '["違禁物", "供犯罪所用之物", "供犯罪預備之物", "犯罪所生之物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00315', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲、乙為鄰居，常為停車吵架，某日甲因乙停車擋住其門口，遂拿出球棒毆打乙，乙被追打100公尺，其 頭部、背部共被打中4次。甲犯罪之罪質為何？', '["連續犯", "接續犯", "集合犯", "加重結果犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00316', 'judicial-57112235', 'judicial-57112235-moex-112-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關刑法第51條數罪併罰定應執行刑規定，下列敘述何者錯誤？', '["甲因殺人罪被宣告無期徒刑、因販賣第二級毒品罪被宣告有期徒刑8年，併科罰金新臺幣50萬元，二 罪只需執行無期徒刑即可", "甲因販賣第二級毒品犯五罪，各被宣告有期徒刑8年、7年6月、8年3月、9年、8年6月，五罪定其 應執行刑，最低不得低於有期徒刑9年，最高不得逾有期徒刑30年", "甲因犯毀損器物罪四次，各被宣告拘役40日、30日、30日、50日，四罪定其應執行刑，最低不得低於 拘役50日，最高不得逾120日", "甲因違反投票行賄罪二罪，各被宣告有期徒刑1年2月、褫奪公權2年，1年3月、褫奪公權3年，二 罪就褫奪公權部分，只要執行3年即可"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
